import json
import sys
import os
import re

def main():
    if len(sys.argv) < 2:
        sys.exit(1)

    workspace_root = sys.argv[1]
    badge_report_path = os.path.join(workspace_root, 'badge_access_analysis.md')

    if not os.path.exists(badge_report_path):
        sys.exit(1)

    with open(badge_report_path, 'r') as f:
        lines = f.readlines()

    badge_hours = []
    amy_chen_hours = 0.0

    table_started = False
    for line in lines:
        if "Discrepancy by Nurse" in line:
            table_started = True
            continue

        if table_started:
            if "---" in line or "Badge Avg" in line:
                continue

            if "|" in line:
                cols = [c.strip() for c in line.split("|")]
                # Table: | ID | Name | Badge Avg (h/week) | CareScheduler Avg (h/week) | Discrepancy (h/week) | Category |
                # Indices: [0]:empty, [1]:ID, [2]:Name, [3]:Badge Avg, [4]:CareScheduler, [5]:Discrepancy, [6]:Category, [7]:empty
                if len(cols) >= 6:
                    try:
                        name = cols[2]
                        badge_val = float(cols[3])

                        badge_hours.append(badge_val)
                        if "Amy Chen" in name:
                            amy_chen_hours = badge_val
                    except (ValueError, IndexError):
                        continue

    if not badge_hours:
        sys.exit(1)

    nurses_above_48h_badge = sum(1 for h in badge_hours if h > 48)
    nurses_above_60h_badge = sum(1 for h in badge_hours if h > 60)
    avg_badge_hours = sum(badge_hours) / len(badge_hours)

    result = {
        "nurses_above_48h_badge": nurses_above_48h_badge,
        "nurses_above_60h_badge": nurses_above_60h_badge,
        "amy_chen_badge_hours": round(amy_chen_hours, 1),
        "avg_badge_hours": round(avg_badge_hours, 1)
    }

    print(json.dumps(result))

if __name__ == "__main__":
    main()
